import{_ as a,o as e,c as n,a0 as s}from"./chunks/framework.D7EjqxMK.js";const c=JSON.parse('{"title":"Agent 操作系统","description":"","frontmatter":{},"headers":[],"relativePath":"06-agent/05_前沿趋势/03_Agent操作系统.md","filePath":"06-agent/05_前沿趋势/03_Agent操作系统.md"}'),r={name:"06-agent/05_前沿趋势/03_Agent操作系统.md"};function o(d,t,l,i,h,p){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="agent-操作系统" tabindex="-1">Agent 操作系统 <a class="header-anchor" href="#agent-操作系统" aria-label="Permalink to &quot;Agent 操作系统&quot;">​</a></h1><blockquote><p><strong>在知识图谱中的位置</strong>：模块五 · 05_前沿趋势 · 第 3 节 <strong>难度</strong>：⭐⭐ | <strong>前置知识</strong>：Agent 基础</p></blockquote><hr><h2 id="_1-概述" tabindex="-1">1. 概述 <a class="header-anchor" href="#_1-概述" aria-label="Permalink to &quot;1. 概述&quot;">​</a></h2><p><strong>Agent OS</strong> 是未来操作系统的形态——Agent 不再只是应用，而是操作系统本身。</p><p>核心理念：未来的电脑/手机/服务器，由 Agent 管理一切——文件、应用、网络、硬件。</p><hr><h2 id="_2-愿景" tabindex="-1">2. 愿景 <a class="header-anchor" href="#_2-愿景" aria-label="Permalink to &quot;2. 愿景&quot;">​</a></h2><h3 id="_2-1-当前-vs-未来" tabindex="-1">2.1 当前 vs 未来 <a class="header-anchor" href="#_2-1-当前-vs-未来" aria-label="Permalink to &quot;2.1 当前 vs 未来&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前:</span></span>
<span class="line"><span>用户 → UI 界面 → 应用程序 → 操作系统 → 硬件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>未来:</span></span>
<span class="line"><span>用户 → 自然语言 → Agent OS → 管理一切应用/资源 → 硬件</span></span></code></pre></div><h3 id="_2-2-agent-os-的核心能力" tabindex="-1">2.2 Agent OS 的核心能力 <a class="header-anchor" href="#_2-2-agent-os-的核心能力" aria-label="Permalink to &quot;2.2 Agent OS 的核心能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><strong>意图理解</strong></td><td>理解用户目标，自动执行</td></tr><tr><td><strong>应用编排</strong></td><td>自动选择和调用应用</td></tr><tr><td><strong>资源管理</strong></td><td>自动管理 CPU/内存/存储</td></tr><tr><td><strong>安全管控</strong></td><td>自动识别和隔离风险</td></tr><tr><td><strong>个性化</strong></td><td>根据用户习惯自适应</td></tr></tbody></table><hr><h2 id="_3-当前进展" tabindex="-1">3. 当前进展 <a class="header-anchor" href="#_3-当前进展" aria-label="Permalink to &quot;3. 当前进展&quot;">​</a></h2><h3 id="_3-1-已出现的方向" tabindex="-1">3.1 已出现的方向 <a class="header-anchor" href="#_3-1-已出现的方向" aria-label="Permalink to &quot;3.1 已出现的方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方向</th><th>代表</th></tr></thead><tbody><tr><td><strong>AI Desktop</strong></td><td>Claude Desktop, Cursor</td></tr><tr><td><strong>AI Search</strong></td><td>Perplexity, Google AI Search</td></tr><tr><td><strong>AI OS</strong></td><td>Windows Copilot, Android Agent</td></tr><tr><td><strong>AI Server</strong></td><td>OpenClaw, Home Assistant</td></tr></tbody></table><h3 id="_3-2-agent-os-成熟度" tabindex="-1">3.2 Agent OS 成熟度 <a class="header-anchor" href="#_3-2-agent-os-成熟度" aria-label="Permalink to &quot;3.2 Agent OS 成熟度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2025: 辅助 Agent（Copilot 模式）</span></span>
<span class="line"><span>2026: 半自主 Agent（可部分自动化）</span></span>
<span class="line"><span>2027: 全自主 Agent（操作系统级别）</span></span></code></pre></div><hr><h2 id="_4-参考资料" tabindex="-1">4. 参考资料 <a class="header-anchor" href="#_4-参考资料" aria-label="Permalink to &quot;4. 参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2601.02749" target="_blank" rel="noreferrer">The Path Ahead for Agentic AI</a></li></ul>`,21)])])}const _=a(r,[["render",o]]);export{c as __pageData,_ as default};
